import sys
from typing import List

class Solution:
    def totalFruit(self, fruits: List[str]) -> int:
        if not fruits:
            return 0

        char_count = {}
        left = 0
        max_fruits = 0

        for right in range(len(fruits)):
            char_count[fruits[right]] = char_count.get(fruits[right], 0) + 1

            while len(char_count) > 2:
                char_count[fruits[left]] -= 1
                if char_count[fruits[left]] == 0:
                    del char_count[fruits[left]]
                left += 1

            max_fruits = max(max_fruits, right - left + 1)

        return max_fruits

