#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int totalFruit(vector<char>& fruits) {
        if (fruits.empty()) {
            return 0;
        }

        unordered_map<char, int> charCount;
        int left = 0;
        int maxFruits = 0;

        for (int right = 0; right < fruits.size(); ++right) {
            charCount[fruits[right]]++;

            while (charCount.size() > 2) {
                charCount[fruits[left]]--;
                if (charCount[fruits[left]] == 0) {
                    charCount.erase(fruits[left]);
                }
                left++;
            }

            maxFruits = max(maxFruits, right - left + 1);
        }

        return maxFruits;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<char> fruits(n);
    for (int i = 0; i < n; i++) cin >> fruits[i];
    Solution sol;
    int ans = sol.totalFruit(fruits);
    cout << ans << "\n";
    return 0;
}
